final_files.sections/testimonial-cards.liquid:
{% liquid
  assign max_items = section.blocks.size
%}

<div class="section-background color-{{ section.settings.color_scheme }}"></div>
<div
  data-testid="testimonial-cards"
  class="
    section
    section--{{ section.settings.section_width }}
    color-{{ section.settings.color_scheme }}
    section-resource-list
    spacing-style
    gap-style
  "
  style="
    {% render 'spacing-style', settings: section.settings %}
    {% render 'gap-style', value: section.settings.gap %}
  "
>
  {% capture list_items %}
    {% for block in section.blocks %}
      <div class="resource-list__item testimonial-card" {{ block.shopify_attributes }}>
        <div class="testimonial-card__content">
          {% if block.settings.quote != blank %}
            <blockquote class="testimonial-card__quote">
              {{ block.settings.quote | escape }}
            </blockquote>
          {% endif %}

          {% if block.settings.rating > 0 %}
            <div class="testimonial-card__rating">
              {% for i in (1..5) %}
                {% if i <= block.settings.rating %}
                  <span class="star star--filled">★</span>
                {% else %}
                  <span class="star star--empty">☆</span>
                {% endif %}
              {% endfor %}
            </div>
          {% endif %}

          {% if block.settings.customer_name != blank %}
            <cite class="testimonial-card__author">
              {{ block.settings.customer_name | escape }}
            </cite>
          {% endif %}
        </div>
      </div>
      {% unless forloop.last %}
        <!--@list/split-->
      {% endunless %}
    {% endfor %}
  {% endcapture %}

  {% liquid
    # Create an array from the list items to be used for different layout types
    assign list_items_array = list_items | strip | split: '<!--@list/split-->'
  %}

  {% render 'resource-list',
    list_items: list_items,
    list_items_array: list_items_array,
    settings: section.settings,
    slide_count: max_items,
    content_type: 'testimonials',
    test_id: 'testimonial-cards-grid'
  %}
</div>

