final_files.sections/countdown-banner.liquid:
{% liquid
  assign end_date = section.settings.end_date
  assign heading = section.settings.heading
  assign background_color = section.settings.background_color
  assign text_color = section.settings.text_color
%}

<div 
  class="section countdown-banner color-{{ section.settings.color_scheme }}"
  style="background-color: {{ background_color }}; color: {{ text_color }};"
  data-testid="countdown-banner-{{ section.id }}"
>
  <div class="countdown-banner__wrapper page-width">
    {% if heading != blank %}
      <h2 class="countdown-banner__heading" style="color: {{ text_color }};">
        {{ heading }}
      </h2>
    {% endif %}

    <div 
      class="countdown-banner__timer"
      data-countdown-end="{{ end_date }}"
      data-testid="countdown-timer"
    >
      <div class="countdown-banner__timer-item">
        <span class="countdown-banner__timer-number" id="countdown-days">00</span>
        <span class="countdown-banner__timer-label">Days</span>
      </div>
      <div class="countdown-banner__timer-item">
        <span class="countdown-banner__timer-number" id="countdown-hours">00</span>
        <span class="countdown-banner__timer-label">Hours</span>
      </div>
      <div class="countdown-banner__timer-item">
        <span class="countdown-banner__timer-number" id="countdown-minutes">00</span>
        <span class="countdown-banner__timer-label">Minutes</span>
      </div>
      <div class="countdown-banner__timer-item">
        <span class="countdown-banner__timer-number" id="countdown-seconds">00</span>
        <span class="countdown-banner__timer-label">Seconds</span>
      </div>
    </div>
  </div>
</div>

<style>
  .countdown-banner {
    padding: 40px 0;
    text-align: center;
  }

  .countdown-banner__wrapper {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 24px;
  }

  .countdown-banner__heading {
    margin: 0;
    font-size: 2rem;
    font-weight: bold;
  }

  .countdown-banner__timer {
    display: flex;
    gap: 32px;
    flex-wrap: wrap;
    justify-content: center;
  }

  .countdown-banner__timer-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 80px;
  }

  .countdown-banner__timer-number {
    font-size: 3rem;
    font-weight: bold;
    line-height: 1;
    display: block;
  }

  .countdown-banner__timer-label {
    font-size: 0.875rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-top: 8px;
  }

  @media screen and (max-width: 749px) {
    .countdown-banner__heading {
      font-size: 1.5rem;
    }

    .countdown-banner__timer {
      gap: 20px;
    }

    .countdown-banner__timer-item {
      min-width: 60px;
    }

    .countdown-banner__timer-number {
      font-size: 2rem;
    }

    .countdown-banner__timer-label {
      font-size: 0.75rem;
    }
  }
</style>

<script>
  function initCountdown() {
    const countdownElement = document.querySelector('[data-countdown-end]');
    if (!countdownElement) return;

    const endDate = countdownElement.dataset.countdownEnd;
    if (!endDate) return;

    const endTime = new Date(endDate).getTime();

    function updateCountdown() {
      const now = new Date().getTime();
      const timeLeft = endTime - now;

      if (timeLeft > 0) {
        const days = Math.floor(timeLeft / (1000 * 60 * 60 * 24));
        const hours = Math.floor((timeLeft % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        const minutes = Math.floor((timeLeft % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((timeLeft % (1000 * 60)) / 1000);

        document.getElementById('countdown-days').textContent = String(days).padStart(2, '0');
        document.getElementById('countdown-hours').textContent = String(hours).padStart(2, '0');
        document.getElementById('countdown-minutes').textContent = String(minutes).padStart(2, '0');
        document.getElementById('countdown-seconds').textContent = String(seconds).padStart(2, '0');
      } else {
        // Countdown ended
        document.getElementById('countdown-days').textContent = '00';
        document.getElementById('countdown-hours').textContent = '00';
        document.getElementById('countdown-minutes').textContent = '00';
        document.getElementById('countdown-seconds').textContent = '00';
      }
    }

    // Update immediately
    updateCountdown();

    // Update every second
    setInterval(updateCountdown, 1000);
  }

  // Initialize when DOM is ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initCountdown);
  } else {
    initCountdown();
  }
</script>

